const incoming = $input.first().json;

const body =
  incoming.body ||
  incoming;

const plan =
  body.implementationPlan ||
  body.plan ||
  {};

const rawName =
  plan.featureName ||
  body.featureName ||
  'unnamed-feature';

const featureName = rawName
  .toLowerCase()
  .replace(/\s+/g, '-')
  .replace(/[^a-z0-9-]/g, '');

const tmpRoot = '/tmp';
const timestamp = Date.now();
const workDir = `${tmpRoot}/logitruck-${featureName}-${timestamp}`;

return [
  {
    json: {
      debugIncomingKeys: Object.keys(incoming),
      debugBodyKeys: Object.keys(body),
      debugPlanKeys: Object.keys(plan),

      project: body.project || 'LogiTruck',
      featureName,
      featureArchetype: plan.featureArchetype || '',
      repoUrl: body.repoUrl || '',
      baseBranch: body.baseBranch || plan.branch || 'main',
      workDir,
      repoDir: `${workDir}/repo`,
      handoffPath: `${workDir}/handoff`,
      plan,
      riskLevel: plan.architectureImpact?.riskLevel || 'low',
      executionLevel: '',
      model: '',
      testsData: { tests: [] },
      implData: { files: [] },
      testsWritten: [],
      filesWritten: [],
      validationOutput: '',
      validationPassed: false,
      status: 'parsed',
      errors: []
    }
  }
];

const data = $input.first().json;
if (data.status === 'rejected') return [{ json: data }];
const plan = data.plan;
const required = ['featureName','featureArchetype','businessIntent','repoContext','architectureImpact','automationScope','files','testingStrategy','factoryExecutionPlan','acceptanceCriteria'];
const validArchetypes = ['utility-feature','mobile-screen-feature','firestore-feature','cloud-function-feature','maps-tracking-feature','native-integration-feature','payments-stripe-connect-feature','ai-support-agent-feature','voice-agent-elevenlabs-feature','landing-react-vite-feature'];
const errors = [];
required.filter(f => !plan[f]).forEach(f => errors.push('Missing required field: ' + f));
if (!validArchetypes.includes(plan.featureArchetype)) errors.push('Invalid featureArchetype: ' + plan.featureArchetype);
if ((!plan.files || (!plan.files.create || !plan.files.create.length)) && (!plan.files || (!plan.files.modify || !plan.files.modify.length))) errors.push('files.create or files.modify must have at least one entry');
if (!plan.testingStrategy || !plan.testingStrategy.commands || !plan.testingStrategy.commands.length) errors.push('testingStrategy.commands must not be empty');
if (errors.length > 0) return [{ json: { ...data, status: 'rejected', errors } }];
return [{ json: { ...data, status: 'validated' } }];

const data = $input.first().json;
const plan = data.plan;
const archetype = plan.featureArchetype;
const risk = (plan.architectureImpact && plan.architectureImpact.riskLevel) || 'low';
const nativeRisk = plan.architectureImpact && plan.architectureImpact.nativeRisk === true;
const levelMap = {
  'utility-feature': 'L0',
  'landing-react-vite-feature': 'L0',
  'mobile-screen-feature': 'L1',
  'ai-support-agent-feature': 'L1',
  'firestore-feature': (risk === 'high' || risk === 'critical') ? 'L2' : 'L1',
  'cloud-function-feature': risk === 'critical' ? 'L2' : 'L1',
  'maps-tracking-feature': nativeRisk ? 'L2' : 'L1',
  'native-integration-feature': 'L2',
  'payments-stripe-connect-feature': 'L2',
  'voice-agent-elevenlabs-feature': 'L2'
};
const executionLevel = levelMap[archetype] || 'L2';
const model = executionLevel === 'L0' ? 'claude-haiku-4-5-20251001' : 'claude-sonnet-4-6';
const maxRetries = (plan.factoryExecutionPlan && plan.factoryExecutionPlan.maxRetries != null) ? plan.factoryExecutionPlan.maxRetries : 2;
return [{ json: { ...data, executionLevel, riskLevel: risk, model, maxRetries, retryCount: 0, retryHistory: [], status: 'classified' } }];

const cmd = $input.first().json;
const data = $('Classify Risk').first().json;
if (cmd.exitCode !== 0) {
  return [{ json: { ...data, status: 'error', errors: [...data.errors, 'Setup sandbox failed: ' + cmd.stderr] } }];
}
return [{ json: { ...data, status: 'sandbox_ready' } }];

const cmd = $input.first().json;
const data = $('After Setup Sandbox').first().json;
if (cmd.exitCode !== 0) {
  return [{ json: { ...data, status: 'error', errors: [...data.errors, 'Clone failed: ' + cmd.stderr] } }];
}
return [{ json: { ...data, status: 'cloned' } }];

const fs = require('fs');
const path = require('path');
const data = $input.first().json;
const plan = data.plan;
const repoDir = data.repoDir;

function safeRead(relativePath) {
  const fullPath = path.join(repoDir, relativePath);
  try {
    if (!fs.existsSync(fullPath)) return `FILE_NOT_FOUND: ${relativePath}`;
    return fs.readFileSync(fullPath, 'utf8');
  } catch (e) {
    return `ERROR_READING_FILE: ${relativePath}\n${e.message}`;
  }
}

function readJson(relativePath) {
  try {
    return JSON.parse(safeRead(relativePath));
  } catch {
    return {};
  }
}

function normalizeBlockName(block) {
  if (!block) return null;
  if (typeof block === 'string') return block.replace(/\.md$/, '');
  const raw = block.name || block.file || block.path;
  if (!raw) return null;
  return String(raw).split('/').pop().replace(/\.md$/, '');
}

// --- Resolución de bloques ---
const registry = readJson('factory/registry/archetype-registry.json');
const archetypeConfig =
  registry[plan.featureArchetype] ||
  registry.archetypes?.[plan.featureArchetype] ||
  {};

const resolvedBuildingBlocks = [
  ...new Set([
    ...(archetypeConfig.defaultBuildingBlocks || []).map(normalizeBlockName),
    ...(plan.selectedBuildingBlocks || []).map(normalizeBlockName)
  ].filter(Boolean))
];

// --- Contenido de los bloques ---
const buildingBlockContents = resolvedBuildingBlocks.map(blockName => {
  const relativePath = `factory/building-blocks/${blockName}.md`;
  const content = safeRead(relativePath);
  return [`# BUILDING BLOCK: ${blockName}`, `# SOURCE: ${relativePath}`, content].join('\n\n');
});

// --- Carga condicional ---
const needsDataModel =
  plan.dataModelsTouched?.length > 0 ||
  resolvedBuildingBlocks.some(b => b.includes('firestore') || b.includes('data-model'));

const needsProjectStructure =
  archetypeConfig.tags?.includes('creates_files') ||
  plan.automationScope?.factoryCanGenerate?.length > 0;

function loadRelevantDataModel() {
  if (!needsDataModel) return null;
  const fullRegistry = readJson('factory/registry/data-model-registry.json');
  const mentionedCollections = (plan.dataModelsTouched || []).map(d => d.collection);
  if (mentionedCollections.length === 0) return JSON.stringify(fullRegistry, null, 2);

  const filtered = {};
  for (const [key, val] of Object.entries(fullRegistry.collections || {})) {
    if (mentionedCollections.includes(key)) filtered[key] = val;
  }
  return JSON.stringify(
    Object.keys(filtered).length > 0 
      ? { ...fullRegistry, collections: filtered } 
      : fullRegistry, 
    null, 2
  );
}

// --- Contexto sin duplicar el plan ---
const contextSections = [
  `# FACTORY CLAUDE RULES\n${safeRead('factory/CLAUDE.md')}`,
  `# ARCHETYPE\n# SOURCE: factory/archetypes/${plan.featureArchetype}.md\n${safeRead(`factory/archetypes/${plan.featureArchetype}.md`)}`,
  `# ARCHETYPE CONFIG\n${JSON.stringify(archetypeConfig, null, 2)}`,
];

if (needsProjectStructure) {
  contextSections.push(`# PROJECT STRUCTURE REGISTRY\n${safeRead('factory/registry/project-structure-registry.json')}`);
}

const dataModelContent = loadRelevantDataModel();
if (dataModelContent) {
  contextSections.push(`# FIRESTORE DATA MODEL REGISTRY (collections relevantes: ${(plan.dataModelsTouched||[]).map(d=>d.collection).join(', ')})\n${dataModelContent}`);
}

// --- Load referenceFiles from plan (gold reference files from production codebase) ---
const referenceFiles = (plan.repoContext?.referenceFiles || []);
const referenceFileContents = referenceFiles
  .map(filePath => {
    const content = safeRead(filePath);
    if (content.startsWith('FILE_NOT_FOUND') || content.startsWith('ERROR_READING')) return null;
    return [
      `# GOLD REFERENCE FILE: ${filePath}`,
      `# This is a production file. Follow its patterns exactly.`,
      content
    ].join('\n\n');
  })
  .filter(Boolean);

contextSections.push(...buildingBlockContents);
if (referenceFileContents.length > 0) {
  contextSections.push(...referenceFileContents);
}

const contextBundle = contextSections.join('\n\n---\n\n');

// --- Archivos a crear/modificar (extraído del plan) ---
const filesToCreate = plan.files?.create || [];
const filesToModify = plan.files?.modify || [];
const doNotTouch = plan.files?.doNotTouch || [];

// --- llmPrompt limpio, sin duplicar el plan ---
// CRÍTICO: instrucción de JSON al inicio Y al final, sin markdown
const llmPrompt = `You are the LogiTruck Factory implementation generator.

CRITICAL OUTPUT RULES:
- Return ONLY raw valid JSON
- Do NOT use markdown code fences (\`\`\`json or \`\`\`)
- Do NOT add any text before or after the JSON object
- Do NOT explain anything
- The response must start with { and end with }

IMPLEMENTATION PLAN:
${JSON.stringify(plan, null, 2)}

FACTORY CONTEXT:
${contextBundle}

GENERATED TESTS — make these pass:
${JSON.stringify(data.testsData || {}, null, 2)}

FILES TO CREATE:
${JSON.stringify(filesToCreate, null, 2)}

FILES TO MODIFY:
${JSON.stringify(filesToModify, null, 2)}

DO NOT TOUCH:
${JSON.stringify(doNotTouch, null, 2)}

EXISTING PATTERNS TO FOLLOW:
${(plan.repoContext?.existingPatternsToFollow || []).join('\n')}

ANTI-PATTERNS TO AVOID:
${(plan.repoContext?.knownAntiPatternsToAvoid || []).join('\n')}

Output exactly this JSON shape (raw, no markdown):
{"files":[{"filePath":"path/to/file.js","content":"full file content here"}]}`;

return [{
  json: {
    ...data,
    plan: {
      ...plan,
      resolvedBuildingBlocks
    },
    contextBundle,
    llmPrompt,
    loadedBuildingBlocks: resolvedBuildingBlocks,
    status: 'context_loaded'
  }
}];

const data = $input.first().json;
const plan = data.plan;

// Solo lo que realmente necesita el generador de tests
const acceptanceCriteria = (plan.acceptanceCriteria || [])
  .map(c => '- ' + c)
  .join('\n');

const patterns = (plan.repoContext?.existingPatternsToFollow || []).join('\n');
const antiPatterns = (plan.repoContext?.knownAntiPatternsToAvoid || []).join('\n');

const filesToCreate = JSON.stringify(plan.files?.create || [], null, 2);
const testingStrategy = JSON.stringify(plan.testingStrategy || {}, null, 2);

// Del contextBundle solo extraemos los building blocks relevantes para tests
// En lugar de pasar TODO el contextBundle (que es enorme), filtramos solo
// los bloques que el archivo de test necesita conocer
const loadedBlocks = data.loadedBuildingBlocks || [];
const testRelevantBlocks = ['testing-guide', 'callable-function-pattern', 'callable-auth-pattern'];

// Extraer solo las secciones relevantes del contextBundle
function extractBlockSection(contextBundle, blockName) {
  if (!contextBundle) return '';
  const marker = `# BUILDING BLOCK: ${blockName}`;
  const start = contextBundle.indexOf(marker);
  if (start === -1) return '';
  // Buscar el siguiente bloque o fin
  const nextMarker = contextBundle.indexOf('# BUILDING BLOCK:', start + marker.length);
  const end = nextMarker === -1 ? contextBundle.length : nextMarker;
  return contextBundle.slice(start, end).trim();
}

const contextBundle = data.contextBundle || '';
const relevantContext = testRelevantBlocks
  .filter(b => loadedBlocks.includes(b))
  .map(b => extractBlockSection(contextBundle, b))
  .filter(Boolean)
  .join('\n\n---\n\n');

// Determinar el tipo de archivo (Cloud Function vs hook vs utility)
const isCloudFunction = plan.featureArchetype === 'cloud-function-feature';
const useModularSDK = plan.featureArchetype === 'cloud-function-feature';
const moduleSystem = plan.moduleSystem || 'CommonJS';

const modularMockBlock = `NO BABEL HOISTING — transform:{} means jest.mock() is NOT hoisted.
RULE: zero require() calls before the last jest.mock(). ALL mocks first, ALL requires after.
Wrong: const { HttpsError } = require(...) followed by jest.mock(...) — real module loads first.

This function uses MODULAR Firebase Admin SDK: require('firebase-admin/firestore'), require('firebase-admin/auth').
DO NOT mock 'firebase-admin' — different module path, will NOT intercept modular imports.

CORRECT ORDER FOR MODULAR SDK:
  1. jest.mock('firebase-functions/v2/https', () => ({ onCall: h => h, HttpsError: class HttpsError extends Error { constructor(code,msg){super(msg);this.code=code;} } }))
  2. Define module-level variables BEFORE jest.mock() — captured at require('../createXxx') time:
     const mockServerTimestamp = jest.fn(() => 'mock-server-timestamp');
     const mockDocSet = jest.fn().mockResolvedValue(undefined);
     const mockDb = { collection: jest.fn().mockImplementation(() => ({ doc: jest.fn().mockReturnValue({ set: mockDocSet, get: jest.fn().mockResolvedValue({ exists: true, data: () => ({}) }), collection: jest.fn().mockReturnValue({ doc: jest.fn().mockReturnValue({ set: mockDocSet }) }) }) })) };
     const mockAuthCreateUser = jest.fn();
     const mockAuthInstance = { createUser: mockAuthCreateUser };
     jest.mock('firebase-admin/firestore', () => ({ getFirestore: jest.fn(() => mockDb), FieldValue: { serverTimestamp: mockServerTimestamp } }));
     jest.mock('firebase-admin/auth', () => ({ getAuth: jest.fn(() => mockAuthInstance) }));
     — getFirestore() and getAuth() are called at module load — mockDb/mockAuthInstance cannot be replaced later
  3. jest.mock('uuid', () => ({ v4: jest.fn().mockReturnValue('test-vendor-id-123') }))
  4. jest.mock('../../../core/user', () => ({ getUserByEmailSafe: jest.fn() }))
     — path from functions/app/<module>/__tests__/ to functions/core/ is ../../../core/<file>
  5. const { HttpsError } = require('firebase-functions/v2/https');
  6. const { createXxx } = require('../createXxx');
  7. const { getUserByEmailSafe } = require('../../../core/user');
ALWAYS use .mockReturnValue()/.mockResolvedValue() — NEVER .returnValue()/.resolvedValue()

CRITICAL for beforeEach — DO NOT reassign mockDb or mockAuthInstance:
  beforeEach(() => {
    jest.clearAllMocks();
    mockAuthCreateUser.mockResolvedValue({ uid: 'default-uid' });
  });
  Use .mockResolvedValueOnce() per individual test for specific overrides.
- Call the handler directly: const result = await handlerFn(request)
- Do NOT call exports.functionName(request) — extract the handler function first`;

const legacyMockBlock = `NO BABEL HOISTING — transform:{} means jest.mock() is NOT hoisted.
RULE: zero require() calls before the last jest.mock(). ALL mocks first, ALL requires after.
CORRECT ORDER:
  1. jest.mock('firebase-functions/v2/https', () => ({ onCall: h => h, HttpsError: class HttpsError extends Error { constructor(code,msg){super(msg);this.code=code;} } }))
  2. Define module-level variables BEFORE jest.mock():
     const mockServerTimestamp = jest.fn(() => 'mock-server-timestamp');
     const mockDb = { collection: jest.fn().mockReturnValue({ doc: jest.fn().mockReturnValue({ set: jest.fn().mockResolvedValue(undefined), collection: jest.fn().mockReturnValue({ doc: jest.fn().mockReturnValue({ set: jest.fn().mockResolvedValue(undefined) }) }) }) }) };
     const mockAuth = { createUser: jest.fn().mockResolvedValue({ uid: 'mock-uid' }) };
     const mockFirestore = jest.fn(() => mockDb);
     mockFirestore.FieldValue = { serverTimestamp: mockServerTimestamp };
     jest.mock('firebase-admin', () => ({ firestore: mockFirestore, auth: jest.fn(() => mockAuth) }));
     — FieldValue is a STATIC property on mockFirestore, NOT inside the return object
  3. jest.mock('uuid', () => ({ v4: jest.fn().mockReturnValue('test-vendor-id-123') }))
  4. jest.mock('../../../core/user', () => ({ getUserByEmailSafe: jest.fn() }))
     — path from functions/app/<module>/__tests__/ to functions/core/ is ../../../core/<file>
  5. const { HttpsError } = require('firebase-functions/v2/https');
  6. const { handlerFn } = require('../createXxx');
  7. const admin = require('firebase-admin');
  8. const { getUserByEmailSafe } = require('../../../core/user');
ALWAYS use .mockReturnValue()/.mockResolvedValue() — NEVER .returnValue()/.resolvedValue()
- Call the handler directly: const result = await handlerFn(request)
- Do NOT call exports.functionName(request) — extract the handler`;

const hookMockBlock = `- jest.mock firebase/firestore
- jest.mock core/firebase/config
- Use renderHook from @testing-library/react-native`;

const mockBlock = isCloudFunction
  ? (useModularSDK ? modularMockBlock : legacyMockBlock)
  : hookMockBlock;

const llmPrompt =
`You are the LogiTruck Factory test generator.

CRITICAL OUTPUT RULES:
- Return ONLY raw valid JSON
- Do NOT use markdown code fences
- Do NOT wrap in \`\`\`json or \`\`\`
- Do NOT add text before or after the JSON
- Response must start with { and end with }

FEATURE TO TEST:
- Name: ${plan.featureName}
- Archetype: ${plan.featureArchetype}
- Module system: ${moduleSystem}
- Summary: ${plan.summary}

FILES TO CREATE (these are the files that need tests):
${filesToCreate}

TESTING STRATEGY:
${testingStrategy}

ACCEPTANCE CRITERIA (test these behaviors):
${acceptanceCriteria}

EXISTING PATTERNS TO FOLLOW:
${patterns}

ANTI-PATTERNS TO AVOID:
${antiPatterns}

RELEVANT FACTORY CONTEXT (testing patterns and auth patterns only):
${relevantContext}

TEST SCOPE — generate exactly these test cases:
1. Unauthenticated user throws HttpsError('unauthenticated')
2. Missing required field throws HttpsError('invalid-argument')
3. Happy path: successful execution returns correct shape
4. Idempotency: duplicate call reuses existing record
5. Firestore/Auth error throws HttpsError('internal')

SIZE CONSTRAINTS (strict):
- ONE test file only
- Maximum 5 test cases
- Under 150 lines decoded
- Concise mocks — no verbose boilerplate
- No redundant assertions

MOCK REQUIREMENTS for ${isCloudFunction ? 'Cloud Function (CommonJS)' : 'hook/utility'}:
${mockBlock}

Output exactly this JSON shape (raw, no markdown):
{"tests":[{"filePath":"functions/app/carrier/__tests__/createCarrier.test.js","contentBase64":"BASE64_ENCODED_CONTENT"}]}`;

return [
  {
    json: {
      ...data,
      llmPrompt,
      status: 'test_prompt_built'
    }
  }
];

const response = $input.first().json;
const data = $('Load Context Bundle').first().json;

function stripMarkdown(str) {
  if (typeof str !== 'string') return str;
  return str
    .replace(/^```json\s*/m, '')
    .replace(/^```\s*/m, '')
    .replace(/```\s*$/m, '')
    .trim();
}

function tryParseJSON(value) {
  // Ya es objeto
  if (value && typeof value === 'object') return value;
  // Es string — intentar parsear
  if (typeof value === 'string') {
    const cleaned = stripMarkdown(value);
    try {
      return JSON.parse(cleaned);
    } catch {
      return null;
    }
  }
  return null;
}

try {
  // Intentar extraer el objeto parseado desde distintas ubicaciones
  const parsed =
    tryParseJSON(response.output) ||
    tryParseJSON(response.text) ||
    tryParseJSON(response.message) ||
    tryParseJSON(response);

  if (!parsed) {
    throw new Error('No parseable JSON found in LLM response');
  }

  // Normalizar: el modelo a veces devuelve { output: { tests: [...] } }
  // o { tests: [...] } directamente
  const testsArray =
    parsed.tests ||
    parsed.output?.tests ||
    [];

  if (!Array.isArray(testsArray)) {
    throw new Error('tests field is not an array: ' + JSON.stringify(parsed).slice(0, 200));
  }

  const tests = {
    tests: testsArray.map(test => ({
      ...test,
      content:
        test.content ||
        (test.contentBase64
          ? Buffer.from(test.contentBase64, 'base64').toString('utf8')
          : ''),
    }))
  };

  // Validar que al menos un test tiene contenido
  const hasContent = tests.tests.some(t => t.content || t.contentBase64);
  if (!hasContent && tests.tests.length > 0) {
    throw new Error('Tests found but all have empty content/contentBase64');
  }

  return [{
    json: {
      ...data,
      testsData: tests,
      testsWritten: tests.tests.map(t => t.filePath),
      status: 'tests_generated'
    }
  }];

} catch (e) {
  // Capturar suficiente contexto para debuggear sin romper el flujo
  const rawPreview = JSON.stringify(response).slice(0, 800);

  return [{
    json: {
      ...data,
      status: 'error',
      errors: [
        ...(data.errors || []),
        'Failed to parse tests response: ' + e.message
      ],
      debugInfo: {
        errorMessage: e.message,
        responseKeys: Object.keys(response || {}),
        rawPreview
      }
    }
  }];
}

const fs = require('fs');
const path = require('path');

const data = $input.first().json;
const tests = data.testsData?.tests || [];

const repoDir = path.resolve(data.repoDir);
const written = [];

for (const test of tests) {
  if (!test.filePath || !test.content) continue;

  const resolved = path.resolve(repoDir, test.filePath);

  if (!resolved.startsWith(repoDir + path.sep)) {
    return [{
      json: {
        ...data,
        status: 'error',
        errors: [
          ...data.errors,
          `Path traversal blocked: ${test.filePath}`
        ]
      }
    }];
  }

  fs.mkdirSync(path.dirname(resolved), { recursive: true });
  fs.writeFileSync(resolved, test.content, 'utf8');

  written.push(test.filePath);
}

return [{
  json: {
    ...data,
    testsWritten: written,
    status: 'tests_written'
  }
}];

const data = $input.first().json;
const plan = data.plan;

const filesToCreate = JSON.stringify(plan.files?.create || [], null, 2);
const filesToModify = JSON.stringify(plan.files?.modify || [], null, 2);
const doNotTouch = JSON.stringify(plan.files?.doNotTouch || [], null, 2);
const patterns = (plan.repoContext?.existingPatternsToFollow || []).join('\n');
const antiPatterns = (plan.repoContext?.knownAntiPatternsToAvoid || []).join('\n');
const tests = JSON.stringify(data.testsData || { tests: [] }, null, 2);
const contextBundle = data.contextBundle || '';
const loadedBlocks = data.loadedBuildingBlocks || [];

// Extraer solo secciones del contextBundle relevantes para implementación
// El plan ya contiene files.create[].buildingBlocks — usamos eso para saber qué bloques necesita CADA archivo
function extractBlockSection(bundle, blockName) {
  const marker = `# BUILDING BLOCK: ${blockName}`;
  const start = bundle.indexOf(marker);
  if (start === -1) return '';
  const nextMarker = bundle.indexOf('# BUILDING BLOCK:', start + marker.length);
  const end = nextMarker === -1 ? bundle.length : nextMarker;
  return bundle.slice(start, end).trim();
}

function extractSection(bundle, sectionTitle) {
  const marker = `# ${sectionTitle}`;
  const start = bundle.indexOf(marker);
  if (start === -1) return '';
  // Buscar el siguiente separador ---
  const nextSep = bundle.indexOf('\n---\n', start);
  const end = nextSep === -1 ? bundle.length : nextSep;
  return bundle.slice(start, end).trim();
}

// Bloques que realmente necesita la implementación (union de todos los archivos a crear)
const blocksNeededForImpl = new Set();
(plan.files?.create || []).forEach(f => {
  (f.buildingBlocks || []).forEach(b => blocksNeededForImpl.add(b));
});
(plan.files?.modify || []).forEach(f => {
  (f.buildingBlocks || []).forEach(b => blocksNeededForImpl.add(b));
});

// Si no hay buildingBlocks declarados por archivo, usar todos los loadedBlocks
// excepto testing-guide (no necesario para implementación)
const implBlocks = blocksNeededForImpl.size > 0
  ? [...blocksNeededForImpl]
  : loadedBlocks.filter(b => b !== 'testing-guide');

const buildingBlocksContext = implBlocks
  .map(b => extractBlockSection(contextBundle, b))
  .filter(Boolean)
  .join('\n\n---\n\n');

// Meta-contexto: solo CLAUDE.md y ARCHETYPE (no data-model-registry completo)
const claudeRules = extractSection(contextBundle, 'FACTORY CLAUDE RULES');
const archetypeSection = extractSection(contextBundle, 'ARCHETYPE\n# SOURCE:');
const archetypeConfig = extractSection(contextBundle, 'ARCHETYPE CONFIG');

// Data model: solo las colecciones que este feature toca
const dataModelsTouched = (plan.dataModelsTouched || []).map(d => d.collection);
let dataModelContext = '';
if (dataModelsTouched.length > 0) {
  const fullDataModel = extractSection(contextBundle, 'FIRESTORE DATA MODEL REGISTRY');
  // Incluir pero indicar al modelo que se enfoque en las colecciones del plan
  dataModelContext = fullDataModel
    ? `# FIRESTORE DATA MODEL REGISTRY (focus on: ${dataModelsTouched.join(', ')})\n` +
      fullDataModel.replace(/^# FIRESTORE DATA MODEL REGISTRY\n/, '')
    : '';
}

// Ensamblar contexto reducido — sin duplicar el plan
const reducedContext = [
  claudeRules,
  archetypeSection,
  archetypeConfig,
  dataModelContext,
  buildingBlocksContext,
].filter(Boolean).join('\n\n---\n\n');

